 1	import { Td, Tr } from '@patternfly/react-table';
 2	import * as React from 'react';
 3	import CSSTransition from 'react-transition-group/CSSTransition';
 4	import { Record } from '../../../api/ipfix';
 5	import { Column } from '../../../utils/columns';
 6	import { RecordField } from '../../drawer/record/record-field';
 7	import { Size } from '../../dropdowns/table-display-dropdown';
 8	import './netflow-table-row.css';
 9	
10	export interface NetflowTableRowProps {
11	  rowNumber?: number;
12	  allowPktDrops: boolean;
13	  lastRender?: string;
14	  flow: Record;
15	  selectedRecord?: Record;
16	  columns: Column[];
17	  size: Size;
18	  onSelect: (record?: Record) => void;
19	  highlight: boolean;
20	  height?: number;
21	  showContent?: boolean;
22	  tableWidth: number;
23	  isDark?: boolean;
24	}
25	
26	export const NetflowTableRow: React.FC<NetflowTableRowProps> = ({
27	  rowNumber,
28	  allowPktDrops,
29	  lastRender,
30	  flow,
31	  selectedRecord,
32	  columns,
33	  size,
34	  onSelect,
35	  highlight,
36	  height,
37	  showContent,
38	  tableWidth,
39	  isDark
40	}) => {
41	  const nodeRef = React.useRef<HTMLTableRowElement>(null);
42	  const onRowClick = () => {
43	    onSelect(flow);
44	  };
45	
46	  return (
47	    <CSSTransition nodeRef={nodeRef} in={highlight} appear={highlight} timeout={100} classNames="newflow">
48	      <Tr
49	        ref={nodeRef}
50	        id={`netflow-table-row-${rowNumber || 0}`}
51	        data-last-render={lastRender || ''}
52	        data-test={`tr-${flow.key}`}
53	        isRowSelected={flow.key === selectedRecord?.key}
54	        onRowClick={onRowClick}
55	        className="stripped"
56	        style={{ height }}
57	      >
58	        {showContent &&
59	          columns.map(c => (
60	            <Td
61	              data-test={`td-${flow.key}`}
62	              data-test-td-column-id={c.id}
63	              data-test-td-value={c.value && c.value(flow)}
64	              key={c.id}
65	              style={{ height: '100%', width: `${Math.floor((100 * c.width) / tableWidth)}%` }}
66	            >
67	              {
68	                <RecordField
69	                  allowPktDrops={allowPktDrops}
70	                  flow={flow}
71	                  column={c}
72	                  size={size}
73	                  useLinks={false}
74	                  isDark={isDark}
75	                />
76	              }
77	            </Td>
78	          ))}
79	      </Tr>
80	    </CSSTransition>
81	  );
82	};
83	
84	export default NetflowTableRow;

